import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.PreparedStatement;
import java.sql.SQLException;

public class BankAccount {
    private static final String DB_URL = "jdbc:mysql://localhost:3306/bank";
    private static final String USER = "root";
    private static final String PASS = "";

    public synchronized void processTransaction(String accountNumber, double amount) throws SQLException {
        Connection conn = DriverManager.getConnection(DB_URL, USER, PASS);
        try (PreparedStatement pstmt = conn.prepareStatement("SELECT balance FROM accounts WHERE account_number = ?")) {
            pstmt.setString(1, accountNumber);
            try (ResultSet rs = pstmt.executeQuery()) {
                if (!rs.next()) {
                    System.out.println("Account not found");
                    return;
                }
                double currentBalance = rs.getDouble("balance");

                if (amount <= 0) {
                    System.out.println("Invalid transaction amount");
                    return;
                }

                PreparedStatement pstmt2 = conn.prepareStatement("UPDATE accounts SET balance = ? WHERE account_number = ?");
                pstmt2.setDouble(1, currentBalance + amount);
                pstmt2.setString(2, accountNumber);
                pstmt2.executeUpdate();
            }
        } finally {
            if (conn != null) {
                conn.close();
            }
        }
    }

    public static void main(String[] args) throws SQLException {
        BankAccount bankAccount = new BankAccount();
        bankAccount.processTransaction("12345", 100.0);
    }
}